 17	export interface AgentDefinitionsAdapterResult {
 18	  actions: FileWriteDeployAction[];
 19	  warnings: PlanWarning[];
 20	}
 21	
 22	/**
 23	 * Compiles deploy actions for agentDefinitions manifest entries.
 24	 *
 25	 * Agent definition files are Markdown files (typically with YAML frontmatter)
 26	 * that define custom agents or subagents for a given platform. Unlike
 27	 * agentRules (which target a single shared global file per agent), each
 28	 * definition entry produces a separate file named after the entry in the
 29	 * agent's dedicated agent-definitions directory (repo-local).
 30	 *
 31	 * Target paths use the `{repo}` placeholder so definitions land in the
 32	 * repository being deployed, not the user's home directory.
 33	 */
 34	export async function compileAgentDefinitionActions(
 35	  entry: AgentDefinitionEntry,
 36	  sourceDir: string,
 37	  resolvedSourceDir: string,
 38	  realRoot: string,
 39	  detectedAgents: AgentId[],
 40	  home: string,
 41	  repo?: string,
 42	): Promise<AgentDefinitionsAdapterResult> {
 43	  const actions: FileWriteDeployAction[] = [];
 44	  const warnings: PlanWarning[] = [];
 45	  const platform = getPlatformKey();
 46	  const targetAgents = entry.agents.filter((agentId) =>
 47	    detectedAgents.includes(agentId),
 48	  );
 49	  const supportedTargets: Array<{
 50	    agentId: AgentId;
 51	    confidence: FileWriteDeployAction["confidence"];
 52	    target: string;
 53	  }> = [];
 54	
 55	  if (targetAgents.length === 0) {
 56	    return { actions, warnings };
 57	  }
 58	
 59	  for (const agentId of targetAgents) {
 60	    const agent = AGENT_REGISTRY_BY_ID[agentId];
 61	    const support = agent?.agentDefinitionsSupport;
 62	    if (!support || support.status === "unsupported") {
 63	      warnings.push({
 64	        kind: "confidence",
 65	        message: `agentDefinitions: agent "${agentId}" uses ${support?.schemaLabel ?? "an unsupported agent-definition schema"} and ${support?.status === "unsupported" ? support.reason : "does not expose a supported agent-definitions adapter"} — skipping "${entry.name}"`,
 66	      });
 67	      continue;
 68	    }
 69	    if (support.status === "planned") {
 70	      warnings.push({
 71	        kind: "confidence",
 72	        message: `agentDefinitions: agent "${agentId}" agent-definitions support is planned via ${support.plannedSurface} — skipping "${entry.name}" until that surface is implemented`,
 73	      });
 74	      continue;
 75	    }
 76	
 77	    supportedTargets.push({
 78	      agentId,
 79	      confidence: agent.provenance.agentDefinitions ?? "provisional",
 80	      target: resolvePlaceholders(
 81	        support.path[platform],
 82	        entry.name,
 83	        home,
 84	        repo,
 85	      ),
 86	    });
 87	  }
 88	
 89	  if (supportedTargets.length === 0) {
 90	    return { actions, warnings };
 91	  }
 92	
 93	  // Validate the shared source file only when at least one target is active.
 94	  const source = path.resolve(sourceDir, entry.path);
 95	  await validateSourcePath(source, entry.path, resolvedSourceDir, realRoot);
 96	  await validateSourceFile(source, entry.path);
 97	
 98	  for (const target of supportedTargets) {
 99	    validateAgentRuleMarkdownPath(entry.path, target.agentId);
100	    actions.push({
101	      kind: "file-write",
102	      skill: entry.name,
103	      agent: target.agentId,
104	      source,
105	      target: target.target,
106	      confidence: target.confidence,
107	    });
108	  }
109	
110	  return { actions, warnings };
111	}
112	
113	export function compileAgentDefinitionReverts(
114	  entry: AgentDefinitionEntry,
115	  agentFilter: AgentId[] | null,
116	  home: string,
117	  repo?: string,
118	): FileWriteRevertAction[] {
119	  const actions: FileWriteRevertAction[] = [];
120	  const platform = getPlatformKey();
121	
122	  for (const agentId of entry.agents) {
123	    if (agentFilter && !agentFilter.includes(agentId)) continue;
124	    const agent = AGENT_REGISTRY_BY_ID[agentId];
125	    const support = agent?.agentDefinitionsSupport;
126	    if (
127	      !support ||
128	      support.status === "unsupported" ||
129	      support.status === "planned"
130	    )
131	      continue;
132	    const target = resolvePlaceholders(
133	      support.path[platform],
134	      entry.name,
135	      home,
136	      repo,
137	    );
138	    actions.push({
139	      kind: "file-write",
140	      skill: entry.name,
141	      agent: agentId,
142	      target,
143	    });
144	  }
145	  return actions;
146	}

